const reduceMotion = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
let quoteInView = false;

const supportedPhotoPattern = /\.(jpe?g|png|hei[cf])$/i;
const supportedPhotoTypes = new Set(["image/jpeg", "image/png", "image/heic", "image/heif"]);

const trackEvent = (name, properties = {}) => {
  window.dataLayer = window.dataLayer || [];
  window.dataLayer.push({ event: name, ...properties });
  if (typeof window.plausible === "function") window.plausible(name, { props: properties });
};

const initializeAnalytics = () => {
  const domain = window.URBAN_YARDS_CONFIG?.analytics?.plausibleDomain;
  if (!domain) return;
  const script = document.createElement("script");
  script.defer = true;
  script.dataset.domain = domain;
  script.src = "https://plausible.io/js/script.js";
  document.head.appendChild(script);
  window.plausible = window.plausible || function plausible() {
    (window.plausible.q = window.plausible.q || []).push(arguments);
  };
};

initializeAnalytics();

const fileToCompressedPhoto = (file) => new Promise((resolve, reject) => {
  const supportedType = supportedPhotoTypes.has(file.type.toLowerCase());
  if (!supportedType && !supportedPhotoPattern.test(file.name)) {
    reject(new Error(`${file.name} must be a JPG, PNG, HEIC, or HEIF image.`));
    return;
  }
  const reader = new FileReader();
  reader.onerror = () => reject(new Error(`Could not read ${file.name}.`));
  reader.onload = () => {
    const image = new Image();
    image.onerror = () => reject(new Error(`${file.name} is not a supported image.`));
    image.onload = () => {
      const maxDimension = 1600;
      const scale = Math.min(1, maxDimension / Math.max(image.width, image.height));
      const canvas = document.createElement("canvas");
      canvas.width = Math.max(1, Math.round(image.width * scale));
      canvas.height = Math.max(1, Math.round(image.height * scale));
      canvas.getContext("2d").drawImage(image, 0, 0, canvas.width, canvas.height);
      const dataUrl = canvas.toDataURL("image/jpeg", 0.78);
      resolve({
        name: file.name.replace(/\.[^.]+$/, "") + ".jpg",
        type: "image/jpeg",
        data: dataUrl.split(",")[1]
      });
    };
    image.src = reader.result;
  };
  reader.readAsDataURL(file);
});

const setFormStatus = (message, state = "") => {
  success.textContent = message;
  success.className = `form-status wide${state ? ` is-${state}` : ""}`;
  if (message) success.focus();
};

const initializeTurnstile = () => {
  const siteKey = window.URBAN_YARDS_CONFIG?.turnstileSiteKey;
  const container = document.querySelector("#quote-turnstile");
  if (!siteKey || !container) return;
  const script = document.createElement("script");
  script.src = "https://challenges.cloudflare.com/turnstile/v0/api.js?render=explicit";
  script.async = true;
  script.defer = true;
  script.onload = () => window.turnstile.render(container, {
    sitekey: siteKey,
    theme: "light",
    callback: (token) => { container.dataset.token = token; },
    "expired-callback": () => { container.dataset.token = ""; }
  });
  document.head.appendChild(script);
};

initializeTurnstile();

