const buildServiceMap = (elementId, expanded = false) => {
  const map = L.map(elementId, {
    attributionControl: true,
    dragging: true,
    scrollWheelZoom: expanded,
    tap: true,
    zoomControl: true,
  });
  L.tileLayer("https://tile.openstreetmap.org/{z}/{x}/{y}.png", {
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>',
    maxZoom: 19,
  }).addTo(map);
  const outline = L.geoJSON(serviceAreaBoundary, {
    style: {
      color: "#123f31",
      fillColor: "#dce7d4",
      fillOpacity: 0.32,
      lineCap: "round",
      lineJoin: "round",
      opacity: 0.92,
      smoothFactor: 1.2,
      weight: expanded ? 3.5 : 2.25,
    },
  }).addTo(map);
  map.serviceBounds = outline.getBounds();
  map.fitBounds(map.serviceBounds, { padding: expanded ? [28, 28] : [12, 12] });
  return map;
};

const compactServiceMap = buildServiceMap("service-area-map");
const expandedServiceMap = buildServiceMap("expanded-service-area-map", true);

const refreshServiceMaps = () => {
  [compactServiceMap, expandedServiceMap].forEach((map) => {
    if (!map) return;
    const rect = map.getContainer().getBoundingClientRect();
    if (!rect.width || !rect.height) return;
    map.invalidateSize();
    map.fitBounds(map.serviceBounds, { padding: map === expandedServiceMap ? [28, 28] : [18, 18] });
  });
};
window.addEventListener("load", refreshServiceMaps);

const requestedService = new URLSearchParams(window.location.search).get("service");
if (requestedService && serviceSelect) {
  const matchingOption = [...serviceSelect.options].find((option) => option.value === requestedService || option.textContent === requestedService);
  if (matchingOption) serviceSelect.value = matchingOption.value || matchingOption.textContent;
}

