let selectedPropertyType = "residential";
let selectedMonth = new Date().getMonth();

const createList = (target, items) => {
  if (!target) return;
  target.innerHTML = items.map((item) => `<li>${item}</li>`).join("");
};

const getPropertyServices = (monthData, propertyData) => {
  const serviceSet = [...monthData.services];
  propertyData.emphasis.forEach((item) => {
    const alreadyCovered = serviceSet.some((service) => service.toLowerCase().includes(item.toLowerCase()));
    if (!alreadyCovered && serviceSet.length < 7) serviceSet.push(item.replace(/\b\w/g, (letter) => letter.toUpperCase()));
  });
  return serviceSet.slice(0, 7);
};

const updateCalendarDisplay = () => {
  if (!calendarSection) return;

  const monthData = serviceCalendar[selectedMonth];
  const propertyData = propertyTypes[selectedPropertyType];
  const serviceList = getPropertyServices(monthData, propertyData);
  const nextMonths = [1, 2].map((offset) => (selectedMonth + offset) % 12);

  calendarPropertyButtons.forEach((button) => {
    const active = button.dataset.propertyType === selectedPropertyType;
    button.classList.toggle("is-active", active);
    button.setAttribute("aria-pressed", String(active));
  });

  calendarMonthButtons.forEach((button) => {
    const active = Number(button.dataset.month) === selectedMonth;
    button.classList.toggle("is-active", active);
    button.setAttribute("aria-pressed", String(active));
  });

  document.querySelector("#calendar-property-label").textContent = propertyData.label;
  document.querySelector("#calendar-month-title").textContent = `${monthNames[selectedMonth]} Care Plan`;
  document.querySelector("#calendar-property-note").textContent = propertyData.note;
  document.querySelector("#calendar-why").textContent = monthData.why;
  document.querySelector("#calendar-schedule").textContent = monthData.schedule;
  document.querySelector("#calendar-best-title").textContent = `${monthNames[selectedMonth]} Priorities`;

  createList(document.querySelector("#calendar-service-list"), serviceList);
  createList(document.querySelector("#calendar-best-list"), serviceList.slice(0, 3));

  document.querySelector("#calendar-plan-ahead").innerHTML = nextMonths.map((monthIndex) => {
    const plan = serviceCalendar[monthIndex];
    return `<div class="plan-ahead-item"><strong>${monthNames[monthIndex]}</strong><span>${plan.services.slice(0, 3).join(", ")}</span></div>`;
  }).join("");
};

calendarPropertyButtons.forEach((button) => {
  button.addEventListener("click", () => {
    selectedPropertyType = button.dataset.propertyType;
    updateCalendarDisplay();
  });
});

calendarMonthButtons.forEach((button) => {
  button.addEventListener("click", () => {
    selectedMonth = Number(button.dataset.month);
    updateCalendarDisplay();
  });
});

updateCalendarDisplay();

const positionNavIndicator = (link) => {
  if (!link || window.innerWidth <= 760) return;
  const navRect = primaryNav.getBoundingClientRect();
  const linkRect = link.getBoundingClientRect();
  primaryNav.style.setProperty("--nav-indicator-x", `${linkRect.left - navRect.left}px`);
  primaryNav.style.setProperty("--nav-indicator-width", `${linkRect.width}px`);
  primaryNav.style.setProperty("--nav-indicator-opacity", "1");
};

menuToggle.addEventListener("click", () => {
  const open = primaryNav.classList.toggle("is-open");
  menuToggle.setAttribute("aria-expanded", String(open));
  if (!open) closeNavDropdowns();
});

const closeNavDropdowns = () => {
  navDropdowns.forEach((dropdown) => {
    dropdown.classList.remove("is-open");
    dropdown.querySelector(".nav-dropdown-toggle")?.setAttribute("aria-expanded", "false");
  });
};

navDropdowns.forEach((dropdown) => {
  const toggle = dropdown.querySelector(".nav-dropdown-toggle");
  toggle?.addEventListener("click", () => {
    const open = !dropdown.classList.contains("is-open");
    closeNavDropdowns();
    dropdown.classList.toggle("is-open", open);
    toggle.setAttribute("aria-expanded", String(open));
  });
});

primaryNav.querySelectorAll("a").forEach((link) => {
  link.addEventListener("click", () => {
    closeNavDropdowns();
    primaryNav.classList.remove("is-open");
    menuToggle.setAttribute("aria-expanded", "false");
  });
});

document.addEventListener("click", (event) => {
  if (!primaryNav.contains(event.target)) closeNavDropdowns();
});

document.addEventListener("keydown", (event) => {
  if (event.key === "Escape") closeNavDropdowns();
});

form.addEventListener("submit", async (event) => {
  event.preventDefault();
  if (!form.checkValidity()) {
    form.reportValidity();
    return;
  }
  const data = new FormData(form);
  const files = [...form.elements.photos.files];
  if (files.length > 3) {
    setFormStatus("Please attach no more than 3 photos.", "error");
    return;
  }

  submitButton.disabled = true;
  submitButton.classList.add("is-loading");
  submitButton.querySelector("span").textContent = files.length ? "Preparing Photos..." : "Sending...";
  setFormStatus("", "");
  trackEvent("quote_submit_started", { service: String(data.get("service") || "") });

  try {
    const photos = await Promise.all(files.map(fileToCompressedPhoto));
    submitButton.querySelector("span").textContent = "Sending...";
    const response = await fetch("/api/quote", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name: data.get("name"),
        email: data.get("email"),
        phone: data.get("phone"),
        location: data.get("location"),
        service: data.get("service"),
        timeline: data.get("timeline"),
        message: data.get("message"),
        company: data.get("company"),
        turnstileToken: document.querySelector("#quote-turnstile")?.dataset.token || "",
        source: `${document.title} (${window.location.pathname})`,
        photos
      }),
      signal: AbortSignal.timeout(25000)
    });
    const result = await response.json().catch(() => ({}));
    if (!response.ok) throw new Error(result.error || "Your request could not be sent.");

    submitButton.classList.add("is-success");
    submitButton.querySelector("span").textContent = "Request Received";
    setFormStatus("Thank you. Your quote request has been received. We will reply within 1 business day.", "success");
    trackEvent("quote_submit_succeeded", { service: String(data.get("service") || ""), hasPhotos: files.length > 0 });
    form.reset();
    document.querySelector("#quote-turnstile")?.removeAttribute("data-token");
    if (window.turnstile) window.turnstile.reset();
  } catch (error) {
    setFormStatus(`${error.message} You can also call (971) 258-1109 or email team@urbanyards.us.`, "error");
    trackEvent("quote_submit_failed", { reason: error.name === "TimeoutError" ? "timeout" : "delivery" });
    submitButton.querySelector("span").textContent = "Try Again";
  } finally {
    submitButton.disabled = false;
    submitButton.classList.remove("is-loading");
    window.setTimeout(() => submitButton.classList.remove("is-success"), 3000);
  }
});

const revealTargets = document.querySelectorAll(".section-heading, .service-card, .calendar-controls, .calendar-main-card, .calendar-highlight-card, .trust-strip article, .quote-copy, .quote-form, .lower-card");
revealTargets.forEach((target, index) => {
  target.classList.add("reveal");
  target.style.setProperty("--reveal-delay", `${Math.min(index % 4, 3) * 65}ms`);
});

if (reduceMotion) {
  revealTargets.forEach((target) => target.classList.add("is-visible"));
} else {
  const revealObserver = new IntersectionObserver((entries) => {
    entries.forEach((entry) => {
      if (!entry.isIntersecting) return;
      entry.target.classList.add("is-visible");
      revealObserver.unobserve(entry.target);
    });
  }, { threshold: 0.12 });
  revealTargets.forEach((target) => revealObserver.observe(target));
}

const navObserver = new IntersectionObserver((entries) => {
  entries.forEach((entry) => {
    if (!entry.isIntersecting) return;
    navLinks.forEach((link) => link.removeAttribute("aria-current"));
    const active = sectionLinks.find(({ section }) => section === entry.target);
    active?.link.setAttribute("aria-current", "page");
    positionNavIndicator(active?.link);
  });
}, { rootMargin: "-30% 0px -62% 0px" });
sectionLinks.forEach(({ section }) => navObserver.observe(section));
navLinks[0].setAttribute("aria-current", "page");
positionNavIndicator(navLinks[0]);

const quoteObserver = new IntersectionObserver(([entry]) => {
  quoteInView = entry.isIntersecting;
  mobileQuoteBar.classList.toggle("is-hidden", quoteInView || window.scrollY < hero.offsetHeight * 0.6);
}, { threshold: 0.08 });
quoteObserver.observe(document.querySelector("#quote"));

const updateScrollEffects = () => {
  header.classList.toggle("is-compact", window.scrollY > 56);
  mobileQuoteBar.classList.toggle("is-hidden", quoteInView || window.scrollY < hero.offsetHeight * 0.6);
  const scrollableHeight = document.documentElement.scrollHeight - window.innerHeight;
  const scrollProgress = scrollableHeight > 0 ? (window.scrollY / scrollableHeight) * 100 : 0;
  document.documentElement.style.setProperty("--scroll-progress", `${Math.min(scrollProgress, 100)}%`);
};
window.addEventListener("scroll", updateScrollEffects, { passive: true });
window.addEventListener("resize", () => {
  positionNavIndicator(navLinks.find((link) => link.hasAttribute("aria-current")));
  syncServiceAccordions();
  refreshServiceMaps();
});
updateScrollEffects();

if (heroPlaceholder && !reduceMotion && window.matchMedia("(pointer: fine)").matches) {
  heroPlaceholder.addEventListener("pointermove", (event) => {
    const rect = heroPlaceholder.getBoundingClientRect();
    heroPlaceholder.style.setProperty("--glow-x", `${event.clientX - rect.left - 85}px`);
    heroPlaceholder.style.setProperty("--glow-y", `${event.clientY - rect.top - 85}px`);
  });
}

if (!reduceMotion && window.matchMedia("(pointer: fine)").matches) {
  serviceCards.forEach((card) => {
    card.addEventListener("pointermove", (event) => {
      const rect = card.getBoundingClientRect();
      const x = ((event.clientX - rect.left) / rect.width - 0.5) * 5;
      const y = ((event.clientY - rect.top) / rect.height - 0.5) * -5;
      card.style.setProperty("--tilt-x", `${y}deg`);
      card.style.setProperty("--tilt-y", `${x}deg`);
    });
    card.addEventListener("pointerleave", () => {
      card.style.removeProperty("--tilt-x");
      card.style.removeProperty("--tilt-y");
    });
  });
}

const syncServiceAccordions = () => {
  const compact = window.innerWidth <= 520;
  serviceToggles.forEach((toggle, index) => {
    const list = document.querySelector(`#${toggle.getAttribute("aria-controls")}`);
    const open = !compact || index === 0;
    toggle.setAttribute("aria-expanded", String(open));
    list.classList.toggle("is-open", open);
  });
};

serviceToggles.forEach((toggle) => {
  toggle.addEventListener("click", () => {
    if (window.innerWidth > 520) return;
    const list = document.querySelector(`#${toggle.getAttribute("aria-controls")}`);
    const open = toggle.getAttribute("aria-expanded") === "true";
    toggle.setAttribute("aria-expanded", String(!open));
    list.classList.toggle("is-open", !open);
  });
});
syncServiceAccordions();

mapExpand.addEventListener("click", () => {
  mapDialog.showModal();
  window.setTimeout(() => {
    expandedServiceMap.invalidateSize();
    expandedServiceMap.fitBounds(expandedServiceMap.serviceBounds, { padding: [28, 28] });
  }, 0);
});
mapClose.addEventListener("click", () => mapDialog.close());
mapDialog.addEventListener("click", (event) => {
  if (event.target === mapDialog) mapDialog.close();
});

document.querySelector("#copyright-year").textContent = new Date().getFullYear();
